package main

import (
	"log"
	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
)

func main() {
	app := pocketbase.New()

	app.OnServe().BindFunc(func(e *core.ServeEvent) error {
		usersColl, err := e.App.FindCollectionByNameOrId("users")
		if err != nil {
			log.Fatalf("users collection not found: %v", err)
		}

		// Create pending_upload
		_, err = e.App.FindCollectionByNameOrId("pending_upload")
		if err != nil {
			coll := core.NewBaseCollection("pending_upload")
			coll.Fields.Add(&core.RelationField{
				Name:         "user",
				Required:     true,
				CollectionId: usersColl.Id,
				MaxSelect:    1,
			})
			coll.Fields.Add(&core.TextField{
				Name:     "key",
				Required: true,
			})
			coll.Fields.Add(&core.DateField{
				Name:     "expires_at",
				Required: true,
			})

			// Add unique index on key
			coll.AddIndex("idx_pending_upload_key", true, "key", "")

			if err := e.App.Save(coll); err != nil {
				log.Fatalf("failed to save pending_upload: %v", err)
			}
			log.Println("Created pending_upload collection")
		}

		// Create uploads
		_, err = e.App.FindCollectionByNameOrId("uploads")
		if err != nil {
			coll := core.NewBaseCollection("uploads")
			coll.Fields.Add(&core.RelationField{
				Name:         "user",
				Required:     true,
				CollectionId: usersColl.Id,
				MaxSelect:    1,
			})
			coll.Fields.Add(&core.TextField{
				Name:     "key",
				Required: true,
			})

			// Add unique index on key
			coll.AddIndex("idx_uploads_key", true, "key", "")

			if err := e.App.Save(coll); err != nil {
				log.Fatalf("failed to save uploads: %v", err)
			}
			log.Println("Created uploads collection")
		}

		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

